function triangleNumber(nums) {
    nums.sort((a, b) => a - b);
    let count = 0;
    for (let i = 0; i < nums.length; ++i) {
        for (let j = i + 1; j < nums.length; ++j) {
            for (let k = j + 1; k < nums.length; ++k) {
                if (nums[i] + nums[j] > nums[k]) {
                    count++;
                }
                else {
                    break;
                }
            }
        }
    }
    return count;
}
